# https://github.com/jreusser/RosalindSolutions

from library import DNASequence
class TranscribeDnaToRna:
    def __init__(self, instring: str):
        self.instring = DNASequence(instring)

    def transcribe(self) -> str:
        return str(self.instring).replace("T", "U")

if __name__ == "__main__":
    instring = ""
    transcribe_dna_to_rna = TranscribeDnaToRna(instring)
    print(transcribe_dna_to_rna.transcribe())